#include<bits/stdc++.h>
using namespace std;
long long n,x,ans,a[100005],b[100005],m,k;
int main(void){
	cin>>n;
	for(int i=0;i<n;i++)cin>>a[i];
	cin>>m;
	for(int i=1;i<=m;i++){
		cin>>k;
		b[i]=a[k],ans=0;
		for(int j=1;j<=i;j++){
			if(b[j]>b[i]){
				swap(b[i],b[j]);
				++ans;
			}
		}
		cout<<ans<<'\n';
	}
	return false;
}
